			let expr = Parser::new(tokens).parse_all().unwrap();
			println!("Expression: {}", expr);
			let result = engine.run(&expr);
			match result {
				Ok(v) =>
					println!("{}", v.borrow()),
				Err(v) =>
					println!("Failed with {}", v.borrow())
			}
			print!("> ");
